#!/usr/bin/env node
// AUTOGENERATED-DRIVER — generates lighthouserc.json, lychee.toml, workflow YAML
// from build.config.json + scripts/fixtures/lhci-assertions.json.
// See openspec/changes/standardize-build-artifacts/specs/build-config/spec.md.

import { createHash } from "node:crypto";
import {
  existsSync,
  readFileSync,
  statSync,
  writeFileSync,
  mkdirSync,
} from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { argv, env, exit, hrtime } from "node:process";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");
const CONFIG_PATH = join(ROOT, "build.config.json");
const FIXTURE_PATH = join(ROOT, "scripts/fixtures/lhci-assertions.json");

// CI auto-promotes to --check: sync MUST NOT write generated files in CI;
// any drift is the contributor's responsibility to commit locally. CI's
// drift gate fails the build on non-empty diff.
const CI = env.GITHUB_ACTIONS === "true";
const CHECK_MODE = argv.includes("--check") || CI;
const SKIP = env.SKIP_BUILD_SYNC === "1";

if (SKIP) {
  console.log("sync:build-config skipped (SKIP_BUILD_SYNC=1)");
  exit(0);
}

// ---------- Path validation ----------
const PATH_REGEX = /^\.build\/[a-z0-9/_-]+$/;
function validatePaths(obj, prefix = "") {
  for (const [k, v] of Object.entries(obj)) {
    const path = prefix ? `${prefix}.${k}` : k;
    if (typeof v === "string") {
      if (k === "root") {
        if (v !== ".build") fail(`build.config.json: ${path} must be ".build"`);
        continue;
      }
      if (!PATH_REGEX.test(v)) {
        fail(
          `build.config.json: invalid path string at ${path}: ${JSON.stringify(v)} (must match ${PATH_REGEX})`,
        );
      }
      if (/\.\.|\n|`|\$\(|^\//.test(v)) {
        fail(
          `build.config.json: rejected suspicious path at ${path}: ${JSON.stringify(v)}`,
        );
      }
    } else if (v && typeof v === "object") {
      validatePaths(v, path);
    }
  }
}

function fail(msg) {
  console.error(`✗ ${msg}`);
  exit(1);
}

// ---------- Inputs ----------
const buildConfig = JSON.parse(readFileSync(CONFIG_PATH, "utf8"));
validatePaths(buildConfig);

const configSha = createHash("sha256")
  .update(readFileSync(CONFIG_PATH))
  .digest("hex")
  .slice(0, 16);

// ---------- Fast-path mtime check ----------
const inputs = [CONFIG_PATH];
if (existsSync(FIXTURE_PATH)) inputs.push(FIXTURE_PATH);
const outputs = [join(ROOT, "lighthouserc.json"), join(ROOT, "lychee.toml")];
const start = hrtime.bigint();
const allOutputsExist = outputs.every((p) => existsSync(p));
if (allOutputsExist && !CHECK_MODE) {
  const inputMaxMtime = Math.max(...inputs.map((p) => statSync(p).mtimeMs));
  const outputMinMtime = Math.min(...outputs.map((p) => statSync(p).mtimeMs));
  if (inputMaxMtime <= outputMinMtime) {
    const elapsedMs = Number(hrtime.bigint() - start) / 1e6;
    if (elapsedMs > 50) {
      console.warn(
        `# slow-fastpath: mtime check took ${elapsedMs.toFixed(1)}ms`,
      );
    }
    exit(0);
  }
}

// CI write-block has been replaced by CHECK_MODE auto-promotion above.
// In CI, sync runs in check-only mode: any required regeneration becomes
// a non-zero exit (drift gate). Local writes stay enabled.

// ---------- Generators ----------
function emitJson(targetPath, obj) {
  const banner = { $generated: "build.config.json", $sha: configSha };
  const merged = { ...banner, ...obj };
  const body = JSON.stringify(merged, null, 2) + "\n";
  return writeIfChanged(targetPath, body);
}

function emitToml(targetPath, body) {
  const banner =
    `# AUTOGENERATED — do not edit. Source: build.config.json (sha=${configSha}). ` +
    `Run: npm run sync:build-config\n`;
  return writeIfChanged(targetPath, banner + body);
}

function writeIfChanged(targetPath, content) {
  if (existsSync(targetPath)) {
    const current = readFileSync(targetPath, "utf8");
    if (current === content) return { path: targetPath, changed: false };
  }
  if (CHECK_MODE) {
    return { path: targetPath, changed: true, wouldWrite: true };
  }
  mkdirSync(dirname(targetPath), { recursive: true });
  writeFileSync(targetPath, content);
  return { path: targetPath, changed: true };
}

// ---------- lighthouserc.json ----------
// Strip $comment* keys recursively from fixture data before merging into
// generated output. The fixture uses comment sentinels for human readers;
// LHCI tolerates them but they pollute the generated artifact.
function stripComments(value) {
  if (Array.isArray(value)) return value.map(stripComments);
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value)
        .filter(([k]) => !k.startsWith("$comment"))
        .map(([k, v]) => [k, stripComments(v)]),
    );
  }
  return value;
}

let lhciAssertions = {};
if (existsSync(FIXTURE_PATH)) {
  lhciAssertions = stripComments(
    JSON.parse(readFileSync(FIXTURE_PATH, "utf8")),
  );
}
const lhci = {
  ci: {
    collect: {
      staticDistDir: buildConfig.dist,
      // LHCI auto-prepends its internal server's host:port to relative URLs.
      // The fixture supplies path-only entries (e.g. "/platform/") so the
      // generated rc doesn't bake in a host that may collide with the runner.
      url: lhciAssertions.urls ?? ["/"],
    },
    assert: lhciAssertions.assert ?? {},
    upload: {
      target: "filesystem",
      outputDir: buildConfig.reports.lhci,
    },
  },
};

// ---------- lychee.toml ----------
// NOTE: lychee v0.23 dropped `cache_path` as a config key; caching is enabled
// via `cache = true`. The cache directory is controlled by --cache-dir CLI
// flag (lychee defaults to `.lycheecache/` at repo root if not specified).
//
// `.github/workflows/link-check.yml` passes
// `--cache-dir .build/cache/lychee` so the cache lives under the .build
// umbrella. `.gitignore` also lists `.lycheecache/` as defense-in-depth in
// case a future workflow change drops the flag.
const lycheeBody = `cache = true
exclude_path = ["${buildConfig.dist}", "node_modules", "${buildConfig.root}"]
timeout = 30
retry_wait_time = 2
accept = [200, 204, 206, 301, 302, 304, 307, 308, 403, 429]
include_verbatim = true
no_progress = true

# URL exclusions (regex patterns).
exclude = [
  # Development/preview URLs — no server running during link-check.
  "^https?://localhost(?::[0-9]+)?(?:/.*)?$",
  "^https?://127\\\\.0\\\\.0\\\\.1(?::[0-9]+)?(?:/.*)?$",
  # Template-literal placeholders in markdown code samples
  # (e.g. \${repo}, \${commit}, \${path}, percent-encoded variants).
  "\\\\$\\\\{[^}]*\\\\}",
  "%7B.*%7D",
  # Planned future repos (referenced in spec text but not yet created).
  "^https?://github\\\\.com/artagon/content(?:[/?#].*)?$",
  # Routes that ship with update-site-marketing-redesign / brand-assets
  # (not yet on production). Remove after those changes archive.
  "^https?://artagon\\\\.com/(writing|use-cases|standards|brand)(?:[/?#].*)?$",
  "^https?://artagon\\\\.com/og/(use-cases|standards|brand|writing)\\\\.png$",
  # Upstream link rot (acceptable; pinned reference is in archive.org).
  "^https?://playwright\\\\.dev/docs/test-patterns/?$",
  # mailto and external services we shouldn't probe.
  "^mailto:",
]
`;

// ---------- Run ----------
const results = [
  emitJson(join(ROOT, "lighthouserc.json"), lhci),
  emitToml(join(ROOT, "lychee.toml"), lycheeBody),
];

const wrote = results.filter((r) => r.changed);
if (CHECK_MODE && wrote.length > 0) {
  console.error(
    "✗ build config drift — run `npm run sync:build-config` locally and commit:",
  );
  for (const r of wrote) console.error(`  - ${r.path}`);
  exit(1);
}

for (const r of wrote) console.log(`✓ wrote ${r.path}`);
if (wrote.length === 0) console.log("✓ all generated files up-to-date");
